UPDATE "compat_pages" SET "body_md" = 'Совместимость Овна и ещё одного представителя того же знака: Овен привносит в пару качества, которые проявляются через инициативу, скорость и прямое действие, а партнёр с тем же знаком усиливает эти же черты. Оба партнёра принадлежат к стихии огонь — это даёт схожий темп и понятную друг другу логику реакций. Совместимость знаков — это общий ориентир: реальная динамика пары определяется полными натальными картами обоих партнёров.', "updated_at" = now()
WHERE "sign_a" = 'oven' AND "sign_b" = 'oven' AND "body_md" IS NULL;

