UPDATE "compat_pages" SET "body_md" = 'Совместимость Водолея и Рыб: Водолей привносит в пару качества, которые проявляются через независимость мышления, нестандартность и интерес к общему благу, а Рыбы — качества, которые проявляются через сочувствие, воображение и тонкую восприимчивость. Разные стихии (воздух и вода) создают контраст, который может быть как источником притяжения, так и точкой трения — многое зависит от готовности слышать различия. Совместимость знаков — это общий ориентир: реальная динамика пары определяется полными натальными картами обоих партнёров.', "updated_at" = now()
WHERE "sign_a" = 'vodoley' AND "sign_b" = 'ryby' AND "body_md" IS NULL;

UPDATE "compat_pages" SET "body_md" = 'Совместимость Рыб и ещё одного представителя того же знака: Рыбы привносит в пару качества, которые проявляются через сочувствие, воображение и тонкую восприимчивость, а партнёр с тем же знаком усиливает эти же черты. Оба партнёра принадлежат к стихии вода — это даёт схожий темп и понятную друг другу логику реакций. Совместимость знаков — это общий ориентир: реальная динамика пары определяется полными натальными картами обоих партнёров.', "updated_at" = now()
WHERE "sign_a" = 'ryby' AND "sign_b" = 'ryby' AND "body_md" IS NULL;
